            /// <summary>
            /// Returns the hash for a shader by name.
            /// Accepts fallback names in the form "_0xABCD".
            /// </summary>
            public static uint GetHash(string name)
            {
                if (name.StartsWith("_0x", StringComparison.OrdinalIgnoreCase))
                {
                    return Convert.ToUInt32(name.Substring(3), 16);
                }
                else
                {
                    return ByName[name].Hash;
                }
            }
            /// <summary>
            /// Returns the name for a hash, or a fallback "_0xABCD" string.
            /// </summary>
            public static string GetName(uint hash)
                => ByHash.TryGetValue(hash, out var so) ? so.Name : $"_0x{hash:X}";
        }

